sourcesContent:
import React, { useState } from "react";
import "../css/Ownerdashboard.css";
import {
  FaHome, FaPlus, FaEdit, FaTrash, FaBell,
  FaCommentDots, FaCalendarAlt, FaCheckCircle,
  FaTimesCircle, FaClock, FaMapMarkerAlt,
  FaBed, FaBath, FaRulerCombined, FaCamera,
  FaSignOutAlt, FaChevronRight, FaEye,
  FaChartBar, FaArrowRight, FaTimes,
  FaCloudUploadAlt, FaUserTie
} from "react-icons/fa";

/* ─── MOCK OWNER ─── */
const OWNER = {
  name: "Madhubalan",
  email: "madhubalan@gmail.com",
  mobile: "+91 73389 00298",
  
  joinedDate: "January 2026",
  verified: true,
};

/* ─── MOCK LISTINGS ─── */
const INIT_LISTINGS = [
  {
    id:1, title:"3BHK Luxury Apartment", type:"Apartment",
    location:"Saravanampatti", price:20000, beds:3, baths:2, area:1350,
    status:"active", views:142, bookings:3,
    image:"https://images.unsplash.com/photo-1545324418-cc1a3fa10c00?w=400&q=80"
  },
  {
    id:2, title:"2BHK Independent House", type:"House",
    location:"Peelamedu", price:15000, beds:2, baths:1, area:950,
    status:"active", views:98, bookings:2,
    image:"https://images.unsplash.com/photo-1560185127-6ed189bf02f4?w=400&q=80"
  },
  {
    id:3, title:"Office Space RS Puram", type:"Office",
    location:"RS Puram", price:25000, beds:null, baths:2, area:800,
    status:"inactive", views:54, bookings:1,
    image:"https://images.unsplash.com/photo-1497366216548-37526070297c?w=400&q=80"
  },
];

/* ─── BOOKING REQUESTS ─── */
const BOOKING_REQUESTS = [
  {
    id:"BK001", propertyTitle:"3BHK Luxury Apartment",
    userName:"Sun", userPhone:"+91 98765 11111",
    visitDate:"Mar 25, 2026", requestedOn:"Mar 18, 2026",
    status:"pending", message:"Interested in long-term rental. Can we meet this weekend?",
    avatar:"https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?w=60&q=80"
  },
  {
    id:"BK002", propertyTitle:"2BHK Independent House",
    userName:"Priya Sharma", userPhone:"+91 98765 22222",
    visitDate:"Mar 28, 2026", requestedOn:"Mar 19, 2026",
    status:"confirmed", message:"Looking for a family-friendly place near schools.",
    avatar:"https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=60&q=80"
  },
  {
    id:"BK003", propertyTitle:"3BHK Luxury Apartment",
    userName:"Karthik Rajan", userPhone:"+91 98765 33333",
    visitDate:"Mar 30, 2026", requestedOn:"Mar 20, 2026",
    status:"rejected", message:"Need immediate availability from April 1st.",
    avatar:"https://images.unsplash.com/photo-1527980965255-d3b416303d12?w=60&q=80"
  },
];

/* ─── MESSAGES ─── */
const MESSAGES = [
  {
    id:1, userName:"Aravind Kumar", propertyTitle:"3BHK Luxury Apartment",
    lastMsg:"Is the apartment still available for April?",
    time:"10:30 AM", unread:2,
    avatar:"https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?w=60&q=80"
  },
  {
    id:2, userName:"Priya Sharma", propertyTitle:"2BHK House",
    lastMsg:"Can you reduce the rent by ₹1000?",
    time:"Yesterday", unread:0,
    avatar:"https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=60&q=80"
  },
  {
    id:3, userName:"Karthik Rajan", propertyTitle:"3BHK Luxury Apartment",
    lastMsg:"What is the security deposit amount?",
    time:"Mar 19", unread:1,
    avatar:"https://images.unsplash.com/photo-1527980965255-d3b416303d12?w=60&q=80"
  },
];

const TABS = [
  { key:"overview",  label:"Overview",  icon:<FaChartBar /> },
  { key:"listings",  label:"Listings",  icon:<FaHome /> },
  { key:"add",       label:"Add Property", icon:<FaPlus /> },
  { key:"bookings",  label:"Requests",  icon:<FaCalendarAlt /> },
  { key:"messages",  label:"Messages",  icon:<FaCommentDots /> },
];

const STATUS_CFG = {
  pending:   { icon:<FaClock />,       label:"Pending",   cls:"pending"   },
  confirmed: { icon:<FaCheckCircle />, label:"Confirmed", cls:"confirmed" },
  rejected:  { icon:<FaTimesCircle />, label:"Rejected",  cls:"rejected"  },
};

/* ─── EMPTY FORM ─── */
const EMPTY_FORM = {
  title:"", type:"Apartment", location:"", price:"",
  deposit:"", beds:"", baths:"", area:"",
  floor:"", furnished:"Semi-Furnished", facing:"East",
  parking:"Open", availableFrom:"", description:"",
};

export default function OwnerDashboard() {
  const [activeTab, setActiveTab]         = useState("overview");
  const [listings, setListings]           = useState(INIT_LISTINGS);
  const [requests, setRequests]           = useState(BOOKING_REQUESTS);
  const [form, setForm]                   = useState(EMPTY_FORM);
  const [editId, setEditId]               = useState(null);
  const [deleteConfirm, setDeleteConfirm] = useState(null);
  const [formSuccess, setFormSuccess]     = useState(false);
  const [activeMsg, setActiveMsg]         = useState(MESSAGES[0]);
  const [replyText, setReplyText]         = useState("");
  const [chatHistory, setChatHistory]     = useState([
    { from:"user",  text:"Is the apartment still available for April?", time:"10:28 AM" },
    { from:"owner", text:"Yes it is! Would you like to schedule a visit?", time:"10:29 AM" },
    { from:"user",  text:"Is the apartment still available for April?", time:"10:30 AM" },
  ]);

  /* ── form change ── */
  const handleForm = (e) => setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  /* ── submit add/edit ── */
  const handleSubmit = (e) => {
    e.preventDefault();
    if (editId) {
      setListings(prev => prev.map(l => l.id === editId
        ? { ...l, ...form, price: Number(form.price), beds: Number(form.beds), baths: Number(form.baths), area: Number(form.area) }
        : l
      ));
      setEditId(null);
    } else {
      setListings(prev => [...prev, {
        ...form, id: Date.now(),
        price: Number(form.price),
        beds: form.beds ? Number(form.beds) : null,
        baths: Number(form.baths),
        area: Number(form.area),
        status:"active", views:0, bookings:0,
        image:"https://images.unsplash.com/photo-1545324418-cc1a3fa10c00?w=400&q=80"
      }]);
    }
    setForm(EMPTY_FORM);
    setFormSuccess(true);
    setTimeout(() => { setFormSuccess(false); setActiveTab("listings"); }, 1800);
  };

  /* ── edit click ── */
  const handleEdit = (listing) => {
    setForm({
      title: listing.title, type: listing.type,
      location: listing.location, price: listing.price,
      deposit: listing.deposit || "", beds: listing.beds || "",
      baths: listing.baths, area: listing.area,
      floor: listing.floor || "", furnished: listing.furnished || "Semi-Furnished",
      facing: listing.facing || "East", parking: listing.parking || "Open",
      availableFrom: listing.availableFrom || "", description: listing.description || "",
    });
    setEditId(listing.id);
    setActiveTab("add");
  };

  /* ── delete ── */
  const handleDelete = (id) => {
    setListings(prev => prev.filter(l => l.id !== id));
    setDeleteConfirm(null);
  };

  /* ── toggle status ── */
  const toggleStatus = (id) => {
    setListings(prev => prev.map(l =>
      l.id === id ? { ...l, status: l.status === "active" ? "inactive" : "active" } : l
    ));
  };

  /* ── booking action ── */
  const handleRequest = (id, action) => {
    setRequests(prev => prev.map(r =>
      r.id === id ? { ...r, status: action } : r
    ));
  };

  /* ── send reply ── */
  const handleReply = (e) => {
    e.preventDefault();
    if (!replyText.trim()) return;
    setChatHistory(prev => [...prev, { from:"owner", text:replyText, time:"Now" }]);
    setReplyText("");
  };

  const totalViews    = listings.reduce((s, l) => s + l.views, 0);
  const totalBookings = listings.reduce((s, l) => s + l.bookings, 0);
  const activeCount   = listings.filter(l => l.status === "active").length;
  const pendingCount  = requests.filter(r => r.status === "pending").length;

  return (
    <div className="od-root">

      {/* ── NAVBAR ── */}
      <nav className="od-nav">
        <a href="/" className="od-logo">RentSpace</a>
        <div className="od-nav-right">
          <span className="od-owner-badge"><FaUserTie /> Owner</span>
          <a href="/login" className="od-logout"><FaSignOutAlt /> Logout</a>
        </div>
      </nav>

      <div className="od-body">

        {/* ── SIDEBAR ── */}
        <aside className="od-sidebar">
          <div className="od-profile-summary">
            <div className="od-avatar-wrap">
              <img src={OWNER.avatar} alt={OWNER.name} />
              <button className="od-avatar-edit"><FaCamera /></button>
            </div>
            <h3>{OWNER.name}</h3>
            <p className="od-role">Property Owner</p>
            {OWNER.verified && (
              <div className="od-verified"><FaCheckCircle /> Verified Owner</div>
            )}
            <p className="od-joined">Since {OWNER.joinedDate}</p>
          </div>

          <div className="od-sidebar-stats">
            <div className="od-ss"><strong>{listings.length}</strong><span>Listings</span></div>
            <div className="od-ss"><strong>{totalViews}</strong><span>Total Views</span></div>
            <div className="od-ss"><strong>{pendingCount}</strong><span>Pending</span></div>
          </div>

          <nav className="od-sidebar-nav">
            {TABS.map(t => (
              <button
                key={t.key}
                className={`od-nav-item ${activeTab === t.key ? "active" : ""}`}
                onClick={() => { setActiveTab(t.key); if(t.key !== "add") { setEditId(null); setForm(EMPTY_FORM); } }}
              >
                <span className="od-nav-icon">{t.icon}</span>
                {t.label}
                {t.key === "bookings" && pendingCount > 0 && (
                  <span className="od-badge-dot">{pendingCount}</span>
                )}
                {t.key === "messages" && (
                  <span className="od-badge-dot">{MESSAGES.reduce((s,m)=>s+m.unread,0)}</span>
                )}
                <FaChevronRight className="od-nav-arrow" />
              </button>
            ))}
          </nav>

          <button className="od-sidebar-logout"><FaSignOutAlt /> Sign Out</button>
        </aside>

        {/* ── MAIN ── */}
        <main className="od-main">

          {/* ══ OVERVIEW ══ */}
          {activeTab === "overview" && (
            <div className="od-tab-content">
              <div className="od-tab-header">
                <h2>Welcome, <em>{OWNER.name.split(" ")[0]}</em> 👋</h2>
                <p>Manage your properties and bookings</p>
              </div>

              <div className="od-stat-cards">
                {[
                  { icon:<FaHome />,        label:"Total Listings",   val:listings.length,  color:"accent"  },
                  { icon:<FaCheckCircle />, label:"Active Listings",  val:activeCount,       color:"green"   },
                  { icon:<FaEye />,         label:"Total Views",      val:totalViews,        color:"accent2" },
                  { icon:<FaCalendarAlt />, label:"Total Bookings",   val:totalBookings,     color:"yellow"  },
                ].map(s => (
                  <div key={s.label} className={`od-stat-card od-stat-${s.color}`}>
                    <div className="od-stat-icon">{s.icon}</div>
                    <div><strong>{s.val}</strong><span>{s.label}</span></div>
                  </div>
                ))}
              </div>

              {/* QUICK ACTIONS */}
              <div className="od-quick-actions">
                <button className="od-qa-btn od-qa-primary" onClick={() => setActiveTab("add")}>
                  <FaPlus /> Add New Property
                </button>
                <button className="od-qa-btn" onClick={() => setActiveTab("listings")}>
                  <FaHome /> View My Listings
                </button>
                <button className="od-qa-btn" onClick={() => setActiveTab("bookings")}>
                  <FaCalendarAlt /> Booking Requests
                  {pendingCount > 0 && <span className="od-qa-badge">{pendingCount}</span>}
                </button>
                <button className="od-qa-btn" onClick={() => setActiveTab("messages")}>
                  <FaCommentDots /> Messages
                </button>
              </div>

              {/* RECENT LISTINGS */}
              <div className="od-section">
                <div className="od-section-header">
                  <h3>My Listings</h3>
                  <button className="od-see-all" onClick={() => setActiveTab("listings")}>
                    See All <FaArrowRight />
                  </button>
                </div>
                <div className="od-mini-listings">
                  {listings.slice(0,2).map(l => (
                    <div key={l.id} className="od-mini-listing">
                      <img src={l.image} alt={l.title} />
                      <div className="od-ml-info">
                        <h4>{l.title}</h4>
                        <p><FaMapMarkerAlt /> {l.location}</p>
                      </div>
                      <div className={`od-listing-status ${l.status}`}>{l.status}</div>
                      <p className="od-ml-price">₹{l.price.toLocaleString()}/mo</p>
                    </div>
                  ))}
                </div>
              </div>

              {/* RECENT REQUESTS */}
              <div className="od-section">
                <div className="od-section-header">
                  <h3>Recent Booking Requests</h3>
                  <button className="od-see-all" onClick={() => setActiveTab("bookings")}>
                    See All <FaArrowRight />
                  </button>
                </div>
                <div className="od-mini-requests">
                  {requests.slice(0,2).map(r => {
                    const st = STATUS_CFG[r.status];
                    return (
                      <div key={r.id} className="od-mini-request">
                        <img src={r.avatar} alt={r.userName} />
                        <div className="od-mr-info">
                          <h4>{r.userName}</h4>
                          <p>{r.propertyTitle}</p>
                        </div>
                        <div className={`od-status-badge ${st.cls}`}>{st.icon} {st.label}</div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          )}

          {/* ══ LISTINGS ══ */}
          {activeTab === "listings" && (
            <div className="od-tab-content">
              <div className="od-tab-header">
                <h2>My Listings</h2>
                <button className="od-add-btn" onClick={() => { setForm(EMPTY_FORM); setEditId(null); setActiveTab("add"); }}>
                  <FaPlus /> Add New
                </button>
              </div>

              {listings.length === 0 ? (
                <div className="od-empty">
                  <FaHome />
                  <h3>No listings yet</h3>
                  <p>Add your first property!</p>
                  <button className="od-empty-btn" onClick={() => setActiveTab("add")}>
                    <FaPlus /> Add Property
                  </button>
                </div>
              ) : (
                <div className="od-listings-grid">
                  {listings.map(l => (
                    <div key={l.id} className={`od-listing-card ${l.status === "inactive" ? "od-inactive" : ""}`}>
                      <div className="od-listing-img-wrap">
                        <img src={l.image} alt={l.title} />
                        <span className={`od-listing-status-tag ${l.status}`}>
                          {l.status === "active" ? "● Active" : "● Inactive"}
                        </span>
                      </div>
                      <div className="od-listing-info">
                        <div className="od-listing-top">
                          <div>
                            <h4>{l.title}</h4>
                            <p><FaMapMarkerAlt /> {l.location}</p>
                          </div>
                          <p className="od-listing-price">₹{l.price.toLocaleString()}<span>/mo</span></p>
                        </div>
                        <div className="od-listing-meta">
                          {l.beds && <span><FaBed /> {l.beds} Beds</span>}
                          <span><FaBath /> {l.baths} Baths</span>
                          <span><FaRulerCombined /> {l.area} sqft</span>
                        </div>
                        <div className="od-listing-stats">
                          <span><FaEye /> {l.views} views</span>
                          <span><FaCalendarAlt /> {l.bookings} bookings</span>
                        </div>
                        <div className="od-listing-actions">
                          <button className="od-edit-btn" onClick={() => handleEdit(l)}>
                            <FaEdit /> Edit
                          </button>
                          <button
                            className={`od-toggle-btn ${l.status === "active" ? "deactivate" : "activate"}`}
                            onClick={() => toggleStatus(l.id)}
                          >
                            {l.status === "active" ? "Deactivate" : "Activate"}
                          </button>
                          <button className="od-delete-btn" onClick={() => setDeleteConfirm(l.id)}>
                            <FaTrash />
                          </button>
                        </div>
                      </div>

                      {/* DELETE CONFIRM */}
                      {deleteConfirm === l.id && (
                        <div className="od-delete-confirm">
                          <p>Delete this listing?</p>
                          <div className="od-dc-actions">
                            <button className="od-dc-yes" onClick={() => handleDelete(l.id)}>Yes, Delete</button>
                            <button className="od-dc-no"  onClick={() => setDeleteConfirm(null)}>Cancel</button>
                          </div>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {/* ══ ADD / EDIT PROPERTY ══ */}
          {activeTab === "add" && (
            <div className="od-tab-content">
              <div className="od-tab-header">
                <h2>{editId ? "Edit Property" : "Add New Property"}</h2>
                <p>{editId ? "Update your property details" : "Fill in the details to list your property"}</p>
              </div>

              {formSuccess && (
                <div className="od-success-banner">
                  <FaCheckCircle /> Property {editId ? "updated" : "added"} successfully!
                </div>
              )}

              <form className="od-property-form" onSubmit={handleSubmit}>

                {/* IMAGE UPLOAD */}
                <div className="od-img-upload">
                  <FaCloudUploadAlt />
                  <p>Click to upload property photos</p>
                  <span>JPG, PNG — Max 5MB each</span>
                </div>

                {/* ROW 1 */}
                <div className="od-form-row">
                  <div className="od-form-field od-full">
                    <label>Property Title *</label>
                    <input name="title" placeholder="e.g. 2BHK Apartment in Peelamedu" value={form.title} onChange={handleForm} required />
                  </div>
                </div>

                {/* ROW 2 */}
                <div className="od-form-row">
                  <div className="od-form-field">
                    <label>Property Type *</label>
                    <select name="type" value={form.type} onChange={handleForm}>
                      {["House","PG","Hostel","Apartment","Office"].map(t => <option key={t}>{t}</option>)}
                    </select>
                  </div>
                  <div className="od-form-field">
                    <label>Location *</label>
                    <select name="location" value={form.location} onChange={handleForm} required>
                      <option value="">Select Location</option>
                      {["Peelamedu","Gandhipuram","RS Puram","Saravanampatti","Singanallur","Hopes College","Tidel Park","Avinashi Road","Ukkadam","Vadavalli"].map(l => <option key={l}>{l}</option>)}
                    </select>
                  </div>
                </div>

                {/* ROW 3 */}
                <div className="od-form-row">
                  <div className="od-form-field">
                    <label>Monthly Rent (₹) *</label>
                    <input name="price" type="number" placeholder="15000" value={form.price} onChange={handleForm} required />
                  </div>
                  <div className="od-form-field">
                    <label>Security Deposit (₹)</label>
                    <input name="deposit" type="number" placeholder="45000" value={form.deposit} onChange={handleForm} />
                  </div>
                </div>

                {/* ROW 4 */}
                <div className="od-form-row">
                  <div className="od-form-field">
                    <label>Bedrooms</label>
                    <input name="beds" type="number" placeholder="2" min="0" value={form.beds} onChange={handleForm} />
                  </div>
                  <div className="od-form-field">
                    <label>Bathrooms *</label>
                    <input name="baths" type="number" placeholder="1" min="1" value={form.baths} onChange={handleForm} required />
                  </div>
                  <div className="od-form-field">
                    <label>Area (sq.ft) *</label>
                    <input name="area" type="number" placeholder="950" value={form.area} onChange={handleForm} required />
                  </div>
                </div>

                {/* ROW 5 */}
                <div className="od-form-row">
                  <div className="od-form-field">
                    <label>Floor</label>
                    <input name="floor" placeholder="e.g. 2nd Floor" value={form.floor} onChange={handleForm} />
                  </div>
                  <div className="od-form-field">
                    <label>Furnished Status</label>
                    <select name="furnished" value={form.furnished} onChange={handleForm}>
                      {["Fully Furnished","Semi-Furnished","Unfurnished"].map(f => <option key={f}>{f}</option>)}
                    </select>
                  </div>
                </div>

                {/* ROW 6 */}
                <div className="od-form-row">
                  <div className="od-form-field">
                    <label>Facing</label>
                    <select name="facing" value={form.facing} onChange={handleForm}>
                      {["East","West","North","South"].map(f => <option key={f}>{f}</option>)}
                    </select>
                  </div>
                  <div className="od-form-field">
                    <label>Parking</label>
                    <select name="parking" value={form.parking} onChange={handleForm}>
                      {["Covered","Open","None"].map(p => <option key={p}>{p}</option>)}
                    </select>
                  </div>
                  <div className="od-form-field">
                    <label>Available From</label>
                    <input name="availableFrom" type="date" value={form.availableFrom} onChange={handleForm} />
                  </div>
                </div>

                {/* DESCRIPTION */}
                <div className="od-form-field od-full">
                  <label>Description</label>
                  <textarea
                    name="description"
                    rows={4}
                    placeholder="Describe your property — location benefits, nearby amenities, special features..."
                    value={form.description}
                    onChange={handleForm}
                  />
                </div>

                <div className="od-form-actions">
                  <button type="submit" className="od-submit-btn">
                    {editId ? <><FaEdit /> Update Property</> : <><FaPlus /> List Property</>}
                  </button>
                  <button type="button" className="od-cancel-btn" onClick={() => { setForm(EMPTY_FORM); setEditId(null); setActiveTab("listings"); }}>
                    Cancel
                  </button>
                </div>

              </form>
            </div>
          )}

          {/* ══ BOOKING REQUESTS ══ */}
          {activeTab === "bookings" && (
            <div className="od-tab-content">
              <div className="od-tab-header">
                <h2>Booking Requests</h2>
                <p>{pendingCount} pending requests</p>
              </div>

              <div className="od-requests-list">
                {requests.map(r => {
                  const st = STATUS_CFG[r.status];
                  return (
                    <div key={r.id} className={`od-request-card od-req-${r.status}`}>
                      <div className="od-request-top">
                        <div className="od-request-user">
                          <img src={r.avatar} alt={r.userName} />
                          <div>
                            <h4>{r.userName}</h4>
                            <p>{r.userPhone}</p>
                          </div>
                        </div>
                        <div className={`od-status-badge ${st.cls}`}>{st.icon} {st.label}</div>
                      </div>
                      <div className="od-request-details">
                        <div className="od-rd-item">
                          <span>Property</span>
                          <strong>{r.propertyTitle}</strong>
                        </div>
                        <div className="od-rd-item">
                          <span>Visit Date</span>
                          <strong>{r.visitDate}</strong>
                        </div>
                        <div className="od-rd-item">
                          <span>Requested On</span>
                          <strong>{r.requestedOn}</strong>
                        </div>
                        <div className="od-rd-item od-rd-full">
                          <span>Message</span>
                          <strong>"{r.message}"</strong>
                        </div>
                      </div>
                      {r.status === "pending" && (
                        <div className="od-request-actions">
                          <button className="od-accept-btn" onClick={() => handleRequest(r.id, "confirmed")}>
                            <FaCheckCircle /> Accept
                          </button>
                          <button className="od-reject-btn" onClick={() => handleRequest(r.id, "rejected")}>
                            <FaTimesCircle /> Reject
                          </button>
                          <a href="/chat" className="od-chat-link">
                            <FaCommentDots /> Chat
                          </a>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* ══ MESSAGES ══ */}
          {activeTab === "messages" && (
            <div className="od-tab-content">
              <div className="od-tab-header">
                <h2>Messages</h2>
                <p>Chat with potential tenants</p>
              </div>

              <div className="od-messages-layout">
                {/* CONVERSATION LIST */}
                <div className="od-conv-list">
                  {MESSAGES.map(m => (
                    <div
                      key={m.id}
                      className={`od-conv-item ${activeMsg?.id === m.id ? "active" : ""}`}
                      onClick={() => setActiveMsg(m)}
                    >
                      <div className="od-conv-avatar-wrap">
                        <img src={m.avatar} alt={m.userName} />
                        {m.unread > 0 && <span className="od-unread-dot">{m.unread}</span>}
                      </div>
                      <div className="od-conv-info">
                        <div className="od-conv-top">
                          <h4>{m.userName}</h4>
                          <span>{m.time}</span>
                        </div>
                        <p>{m.propertyTitle}</p>
                        <p className="od-conv-last">{m.lastMsg}</p>
                      </div>
                    </div>
                  ))}
                </div>

                {/* CHAT WINDOW */}
                {activeMsg && (
                  <div className="od-chat-window">
                    <div className="od-chat-header">
                      <img src={activeMsg.avatar} alt={activeMsg.userName} />
                      <div>
                        <h4>{activeMsg.userName}</h4>
                        <p>{activeMsg.propertyTitle}</p>
                      </div>
                    </div>

                    <div className="od-chat-messages">
                      {chatHistory.map((c, i) => (
                        <div key={i} className={`od-chat-bubble ${c.from === "owner" ? "od-bubble-owner" : "od-bubble-user"}`}>
                          <p>{c.text}</p>
                          <span>{c.time}</span>
                        </div>
                      ))}
                    </div>

                    <form className="od-chat-input" onSubmit={handleReply}>
                      <input
                        type="text"
                        placeholder="Type your reply..."
                        value={replyText}
                        onChange={e => setReplyText(e.target.value)}
                      />
                      <button type="submit"><FaArrowRight /></button>
                    </form>
                  </div>
                )}
              </div>
            </div>
          )}

        </main>
      </div>
    </div>
  );
}
